{action_set_definitions}: {
  "inspect_network_connections": {
    "description": "Retrieves active network connections for a specific host, including source/destination IPs, ports, and associated process IDs (PIDs).",
    "parameters": {
      "type": "object",
      "properties": {
        "host_id": {
          "type": "string",
          "description": "The unique identifier for the host to inspect (e.g., 'srv_mgmt_hub')."
        }
      },
      "required": [
        "host_id"
      ]
    },
    "example_output": {
      "connections": [
        {
          "pid": 1234,
          "local_address": "10.0.0.5:443",
          "remote_address": "203.0.113.10:80",
          "status": "ESTABLISHED",
          "protocol": "TCP"
        }
      ]
    }
  },
  "list_firewall_rules": {
    "description": "Queries the current firewall configuration for all active rules.",
    "parameters": {
      "type": "object",
      "properties": {},
      "required": []
    },
    "example_output": {
      "rules": [
        {
          "rule_id": "fw-99",
          "source": "any",
          "destination": "any",
          "port": "8443",
          "action": "ALLOW"
        }
      ]
    }
  },
  "apply_firewall_rule": {
    "description": "Creates or updates a firewall rule to allow or deny specific traffic. Can be used for containment.",
    "parameters": {
      "type": "object",
      "properties": {
        "direction": {
          "type": "string",
          "enum": [
            "INBOUND",
            "OUTBOUND"
          ],
          "description": "Direction of traffic."
        },
        "source": {
          "type": "string",
          "description": "Source IP or CIDR block."
        },
        "destination": {
          "type": "string",
          "description": "Destination IP or CIDR block."
        },
        "port": {
          "type": "string",
          "description": "The port number or 'any'."
        },
        "protocol": {
          "type": "string",
          "enum": [
            "TCP",
            "UDP",
            "ANY"
          ],
          "description": "The network protocol."
        },
        "action": {
          "type": "string",
          "enum": [
            "ALLOW",
            "DENY"
          ],
          "description": "The action to take on matching traffic."
        }
      },
      "required": [
        "direction",
        "source",
        "destination",
        "port",
        "protocol",
        "action"
      ]
    },
    "example_output": {
      "status": "success",
      "rule_id": "rule_123"
    }
  },
  "manage_process": {
    "description": "Performs actions on host processes such as termination. Does NOT reboot the host.",
    "parameters": {
      "type": "object",
      "properties": {
        "host_id": {
          "type": "string",
          "description": "Target host ID."
        },
        "pid": {
          "type": "integer",
          "description": "The process ID to manage."
        },
        "operation": {
          "type": "string",
          "enum": [
            "KILL",
            "SUSPEND"
          ],
          "description": "The operation to perform."
        }
      },
      "required": [
        "host_id",
        "pid",
        "operation"
      ]
    },
    "example_output": {
      "status": "terminated",
      "pid": 1234
    }
  },
  "remediate_user_account": {
    "description": "Remediates a compromised account by resetting credentials or applying security restrictions. Does not delete the account.",
    "parameters": {
      "type": "object",
      "properties": {
        "username": {
          "type": "string",
          "description": "The username of the account to remediate."
        },
        "action": {
          "type": "string",
          "enum": [
            "RESET_PASSWORD",
            "ROTATE_KEYS",
            "DISABLE_SESSION"
          ],
          "description": "The remediation action."
        }
      },
      "required": [
        "username",
        "action"
      ]
    },
    "example_output": {
      "status": "credentials_rotated",
      "username": "svc_adm_auto"
    }
  },
  "get_host_inventory": {
    "description": "Retrieves internal network topology information to identify specific host roles (e.g., Domain Controllers).",
    "parameters": {
      "type": "object",
      "properties": {},
      "required": []
    },
    "example_output": {
      "nodes": [
        {
          "id": "srv_dc_01",
          "role": "primary_domain_controller",
          "ip": "10.0.0.1"
        }
      ]
    }
  }
